const VKEY = {"protocol":"groth16","curve":"bn128","nPublic":6,"vk_alpha_1":["16692401696937018577177824778270542027705304675171325330641600532409587640895","18178809817714470201780598352936276552367035220759727620174632624518242558535","1"],"vk_beta_2":[["6223253324048712777334558976648340125574594945090518425287972762368775828859","19843774644525535978091607393941233176161879633097628718974054489251557687799"],["20572930412694810980945238352456266430511560895038951082549690154273678773658","21833014505530023490676305252490689829124410976918723304938355352073193628421"],["1","0"]],"vk_gamma_2":[["10857046999023057135944570762232829481370756359578518086990519993285655852781","11559732032986387107991004021392285783925812861821192530917403151452391805634"],["8495653923123431417604973247489272438418190587263600148770280649306958101930","4082367875863433681332203403145435568316851327593401208105741076214120093531"],["1","0"]],"vk_delta_2":[["486250828575091032168745842719268689222992572489231340702780559007646143197","8492869135560675275197177306913723527074636869554099951006171269387102991738"],["5318711425464779979981181869533764361105608097630409795938879769005488640945","19371952454146207249784771009352036798661328352283108360671132832628301776140"],["1","0"]],"vk_alphabeta_12":[[["20353970610916319686419244217748133728827594952778896756548257228394968849243","17617818702883705615693213995412192008606872418921817849985406789668808883555"],["3286727612194590531107671922393686120479168401244935712839958926604513286164","9645969367940419346860410073363019554648136324537973007538596372416071042807"],["11166550823491983812869658490199436891765116095500168390066982911110733198107","9521106449989210018810803343334504378925564245810350930417158044501999946947"]],[["4261665671204895362023332806238594253543239550814869884140307699727950633057","1529921674462138120395754426670998626860165598937493790013491331334477063469"],["9359169451102845158713087920696939122849572407363913686376242938990368010890","11420052311467706988147496444855408123189334215148892380268988436867489044425"],["1464065491560114873359820305865868439226926682378518182289573091478989408415","3601549264513877002888307888209099499444789454642012650385472586399824126769"]]],"IC":[["17620864203645744731745730279466407911674035328821345307686910273669968039683","5750660776522892407495557745758070509023209001652257787159087522946334991910","1"],["10239605232915737334787932495010577907693888504218474368472895531172261196332","13075783901727612690841794585826690550378028142002850700474960341861480565786","1"],["20635017656277317368034252844579507042946451895530581141438702551627520034006","17762576842565042165688068416692138765669246236539462151494586287688358586110","1"],["7785881785076898617910116039065368796431716912416990468503174649147370720725","19067298480252636582409076681846087645787816469571977773826754641596589985923","1"],["19198267210371813820993198359951663323747496699457944400438240936196397980455","3981933457740155240960294952923262561676593294506919085309597130642013395760","1"],["927778505299531371026555962912674682433922239226437574533896011364381063872","5347318225946067349132998141239801207083261932622453495201436476511497586952","1"],["9537147371512238173977683390007663125351207250864071393459884812186018830840","4692710636588244468613317713755325788227743525859199300181802444834049884237","1"]]};

export async function POST(req: Request) {
  const { agent_id, challenge, proof, publicSignals } = await req.json();

  if (!agent_id || !challenge || !proof || !publicSignals) {
    return NextResponse.json(
      { data: null, error: "agent_id, challenge, proof, and publicSignals required" },
      { status: 400 }
    );
  }

  const supabase = getSupabaseServer();

  // Validate challenge: exists, belongs to agent, not expired, not used
  const { data: ch } = await supabase
    .from("zkp_challenges")
    .select("*")
    .eq("challenge", challenge)
    .eq("agent_id", agent_id)
    .eq("used", false)
    .single();

  if (!ch) {
    return NextResponse.json(
      { data: null, error: "Invalid or expired challenge" },
      { status: 400 }
    );
  }

  if (new Date(ch.expires_at) < new Date()) {
    return NextResponse.json(
      { data: null, error: "Challenge expired" },
      { status: 400 }
    );
  }

  // Mark challenge as used (prevent replay)
  await supabase
    .from("zkp_challenges")
    .update({ used: true })
    .eq("id", ch.id);

  // Verify approvedModels in publicSignals[1..5] match expected values
  const expectedModels: string[] = APPROVED_MODEL_IDS.map((v: unknown) => String(v));
  while (expectedModels.length < 5) expectedModels.push("0");
  for (let i = 0; i < 5; i++) {
    if (publicSignals[i + 1] !== expectedModels[i]) {
      return NextResponse.json(
        { data: null, error: "Invalid approved models" },
        { status: 400 }
      );
    }
  }

  // Verify Groth16 proof
  const snarkjs = await import("snarkjs");
  const valid = await snarkjs.groth16.verify(VKEY, publicSignals, proof);

  if (!valid) {
    return NextResponse.json(
      { data: null, error: "ZKP verification failed" },
      { status: 400 }
    );
  }

  const commitment = publicSignals[0];

  // Check commitment uniqueness (prevent same proof reuse across agents)
  const { data: existing } = await supabase
    .from("agents")
    .select("id")
    .eq("zkp_commitment", commitment)
    .single();

  if (existing && existing.id !== agent_id) {
    return NextResponse.json(
      { data: null, error: "Commitment already used by another agent" },
      { status: 409 }
    );
  }

  await supabase
    .from("agents")
    .update({ zkp_verified: true, zkp_commitment: commitment })
    .eq("id", agent_id);

  return NextResponse.json({ data: { verified: true, commitment }, error: null });
}
